options.customCss:
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&display=swap');

/* --- 1. VARIABLES --- */
:root {
    --font-family: 'Inter', sans-serif;
    --font-weight-normal: 400;
    --font-weight-bold: 600;

    /* Dark Theme Colors */
    --color-background: #0d0d0d;
    --color-card-bg: rgba(5, 5, 5, 0.7);
    --color-card-border: #333;
    --color-card-shadow: 0 20px 40px rgba(0,0,0,0.8);

    --color-header: #ffffff;
    --color-label: #e0e0e0;
    --color-input-text: #ffffff;
    --color-input-border: #333333;
    --color-focus-border: #ffffff;

    --color-submit-btn-bg: #ffffff;
    --color-submit-btn-text: #000000;

    /* Dimensions */
    --border-radius-card: 24px;
    --border-radius-input: 12px;
    --submit-btn-height: 48px;
    --padding-card: 40px;
    --container-width: 448px;
}

/* --- 2. BACKGROUND ANIMATION --- */
@keyframes gridMove {
    0% { background-position: 0 0; }
    100% { background-position: 30px 30px; }
}

body {
    background-color: var(--color-background);
    background-image: radial-gradient(circle at 50% 50%, #1a1a1a 0%, #000000 100%);
    min-height: 100vh;
}

body::before {
    content: '';
    position: fixed;
    top: 0; left: 0; width: 100%; height: 100%;
    background-image:
        linear-gradient(rgba(255, 255, 255, 0.05) 1px, transparent 1px),
        linear-gradient(90deg, rgba(255, 255, 255, 0.05) 1px, transparent 1px);
    background-size: 30px 30px;
    z-index: -1;
    animation: gridMove 4s linear infinite;
}

/* --- 3. CARD STYLING --- */
.el-card {
    background-color: var(--color-card-bg) !important;
    border: 1px solid var(--color-card-border) !important;
    border-radius: var(--border-radius-card) !important;
    box-shadow: var(--color-card-shadow) !important;
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
}

/* --- 4. GIF ICON REPLACEMENT (Resized for Visibility) --- */
.form-header::before {
    content: ''; 
    display: block;

    /* INCREASED SIZE: Wider container for banner-style GIF */
    width: 360px; 
    height: 150px;

    margin: 0 auto 10px auto; /* Centers it horizontally */

    /* YOUR CLOUDINARY URL */
    background-image: url('https://res.cloudinary.com/dni3mpsig/image/upload/v1767095907/gloryacq_rqulaa.gif');

    background-repeat: no-repeat;
    background-position: center;
    background-size: contain; /* Keeps the GIF proportional without cropping */

    /* Optional: Remove border if you want a clean look, or keep it */
    /* border: 1px solid rgba(255,255,255,0.1); */
    /* box-shadow: 0 0 20px rgba(255, 255, 255, 0.1); */
}

/* --- 5. INPUTS --- */
.el-input__inner, 
.el-textarea__inner,
input {
    background-color: #1a1a1a !important;
    border: 1px solid var(--color-input-border) !important;
    color: white !important;
    border-radius: var(--border-radius-input) !important;
    padding: 14px !important;
    height: auto !important;
    transition: all 0.2s ease;
}

.el-input__inner:focus, input:focus {
    border-color: var(--color-focus-border) !important;
    box-shadow: 0 0 0 2px rgba(255, 255, 255, 0.1);
}

/* --- 6. BUTTON --- */
button.el-button--primary, button[type="submit"] {
    width: 100%;
    height: var(--submit-btn-height) !important;
    background-color: var(--color-submit-btn-bg) !important;
    color: var(--color-submit-btn-text) !important;
    border-radius: var(--border-radius-input) !important;
    border: none !important;
    font-weight: 600;
    transition: background-color 0.2s;
}

button.el-button--primary:hover {
    background-color: #f0f0f0 !important;
    transform: translateY(-1px);
}

/* --- 7. HIDDEN ELEMENTS --- */
.n8n-form-footer { display: none; }
.test-notice { display: none !important; }

