return $input.all().map(item => {
    const json = item.json;
    if (json.channelUrl) {
        const totalViews = json.viewCount || 0;
        const totalVideos = json.videoCount || 1;
        const calculatedAvg = Math.round(totalViews / totalVideos);

        // --- NORMALIZATION FIX ---
        // remove trailing slash and www. to ensure uniqueness
        let url = json.channelUrl.trim();
        if (url.endsWith('/')) {
            url = url.slice(0, -1);
        }

        return {
            json: {
                channelName: json.channelName || 'Unknown',
                channelUrl: url, // Normalized URL
                channelHandle: json.channelUsername ? '@' + json.channelUsername : '',
                subscriberCount: json.numberOfSubscribers || 0,
                avgViews: calculatedAvg,
                // THIS IS THE "ABOUT" SECTION TEXT
                aboutDescription: json.text || '', 
                description: json.text || '',
                socialLinks: json.descriptionLinks || [],
                avatar: json.avatarUrl || ''
            }
        };
    }
}).filter(item => item !== undefined);

