    // Check for "like@" patterns (scraping buttons)
    if (parts[0].toLowerCase() === 'like' || parts[0].toLowerCase() === 'subscribe') return false;

    const domain = parts[1].toLowerCase();
    if (blacklistedDomains.some(d => domain.includes(d))) return false;
    return true;
  };

