    // Optional: Log filtered channels for debugging
    // else {
    //     console.log(`Filtered: ${channelName} (${country})`);
    // }
}

return results;

// Get the avg_7day_views threshold from Set Input Parameters
let targetViews = 0;
try {
    const inputParams = $('Set Input Parameters2').first();
    if (inputParams && inputParams.json) {
        targetViews = inputParams.json.avg_7day_views || 0;
    }
} catch(e) {
    targetViews = 0;
}

// If no threshold is set, return all items
if (targetViews === 0) {
    return $input.all();
}

// Calculate the range (±20%)
const minViews = targetViews * 0.5;
const maxViews = targetViews * 1.5;

// Filter items where avgViews is within the range
const items = $input.all();
const filtered = items.filter(item => {
    const avgViews = item.json.avgViews || 0;
    return avgViews >= minViews && avgViews <= maxViews;
});

return filtered;

// Get the subscriber_count threshold from Set Input Parameters
let targetSubscribers = 0;
try {
    const inputParams = $('Set Input Parameters2').first();
    if (inputParams && inputParams.json) {
        targetSubscribers = inputParams.json.subscriber_count || 0;
    }
} catch(e) {
    targetSubscribers = 0;
}

// If no threshold is set, return all items
if (targetSubscribers === 0) {
    return $input.all();
}

// Calculate the range (±50%)
const minSubscribers = targetSubscribers * 0.5;
const maxSubscribers = targetSubscribers * 2.5;

// Filter items where subscriberCount is within the range
const items = $input.all();
const filtered = items.filter(item => {
    const subscriberCount = item.json.subscriberCount || 0;
    return subscriberCount >= minSubscribers && subscriberCount <= maxSubscribers;
});

return filtered;

const aiItems = $input.all();

// Get base data from Extract Social & Email
let baseItems = [];
try {
    baseItems = $('Extract Social & Email2').all() || [];
} catch(e) {
    baseItems = [];
}

// Build a map for reliable lookups
const baseMap = new Map();
const normalize = (u) => (u || '').toLowerCase().replace(/^(https?:\/\/)?(www\.)?/, '').replace(/\/$/, '').trim();

baseItems.forEach(item => {
    const url = normalize(item.json.channelUrl);
    if (url) baseMap.set(url, item.json);
});

const results = [];

for (let index = 0; index < aiItems.length; index++) {
    const item = aiItems[index];
    const aiData = item.json.output || item.json;
    const aiUrl = normalize(aiData.channelUrl || item.json.channelUrl);

    // Find original data
    let original = baseMap.get(aiUrl);
    if (!original && baseItems[index]) original = baseItems[index].json;
    if (!original) original = {};

    // ============================================
    // NAME EXTRACTION - FIXED LOGIC
    // ============================================
    let realName = 'Unknown';
    let nameSource = 'none';

    // Priority 1: AI found a name via search
    const aiFoundName = aiData.fullName || aiData.realName;
    if (aiFoundName && aiFoundName !== 'Unknown' && aiFoundName.length > 1) {
        realName = aiFoundName;
        nameSource = aiData.nameOrigin || 'AI Search';
    }
    // Priority 2: Fallback to channel name if AI returned Unknown
    else {
        realName = original.channelName || 'Unknown';
        nameSource = 'Channel Name';
    }

    // Email
    let finalEmail = original.extractedEmailFromAbout || original.email || 'Not Found';
    let finalSource = (finalEmail !== 'Not Found') ? 'Description' : 'None';

    // Website URL
    const websiteUrl = original.extractedUrls ? original.extractedUrls.website : '';

    results.push({
        json: {
            // Preserve all original data
            channelUrl: original.channelUrl || aiData.channelUrl || '',
            channelName: original.channelName || '',
            channelHandle: original.channelHandle || '',
            description: original.description || '',
            aboutDescription: original.aboutDescription || '',
            subscriberCount: original.subscriberCount || 0,
            avgViews: original.avgViews || 0,
            extractedUrls: original.extractedUrls || {},

            // Location data (preserved from earlier)
            detectedCountry: original.detectedCountry || 'Unknown',
            detectedCity: original.detectedCity || '',
            locationConfidence: original.locationConfidence || 'low',
            locationSource: original.locationSource || '',

            // Name data from AI
            realName: realName,
            nameSource: nameSource,
            nameConfidence: aiData.confidence || 'low',
            nameVerificationNote: aiData.verificationNote || '',

            // Email data
            email: finalEmail,
            emailSource: finalSource,

            // Website for next agent
            website_url: websiteUrl
        }
    });
}

return results;
